INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('customs-f19eb2bd-moex-00237', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-112-34c7f7f6', 'sub-customs-f19eb2bd-01', NULL, 'single_choice', '「這時代，很多人感嘆閱讀的人變少了，不過現代生活的確不鼓勵人閱讀， 閱讀帶來的思考很可能讓你更不容易融入這社會的運作裡。現代人有他一 定運作的速度，若不在速度的螺旋上，就是在一連串的雜訊干擾中焦慮地 放空，但閱讀攔截了這種生活形式，閱讀這行為雖然低調，但根本性地反 抗了現代生活推崇的理想形式。」 根據上文，下列選項最符合文意的是：', '["閱讀賦予我們反省當代生活的節奏", "閱讀的焦慮感增加現代生活的困境", "快速閱讀有利於掌握社會的運作邏輯", "影音媒體流行是現代生活的理想形式"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:26+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "151", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00238', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-112-34c7f7f6', 'sub-customs-f19eb2bd-01', NULL, 'single_choice', '一位擅長以客家花布創作的藝術家說到：「鮮豔的印花圖騰具有濃郁的臺 灣色彩，不能將它視為單純的文化象徵，反而是一種追尋自我認同、建立 對話的媒介。使用花布作為素材是為了建立當代藝術與東方傳統的對話， 透過自身的文化探索，突顯出全球化與地方性的關係。」 根據上文，下列選項何者最接近文意？', '["強調當代藝術是一種文化的對話，並不單指一種文化", "藝術創作不需要使用象徵的符號，關鍵在於不期而遇", "使用客家花布創作是為了突顯臺灣文化主體優越性，讓世界看見臺灣", "東西方藝術有著截然不同的特色元素，鮮豔的美感是當代藝術的精髓"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:26+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "151", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00239', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-112-34c7f7f6', 'sub-customs-f19eb2bd-01', NULL, 'single_choice', '「朱老師一輩子編報教書，筆耕不輟，退休後還到報社做事排遣時間。教我 們《新聞英語》那幾年他是報社總編輯。一天，我去看望老師，報館一位見 習生也在，他說最想靠寫作維生，向老師討教。老師說沒什麼好教的，寫作 只靠用功、勤奮，別的不重要。那時我心想老師是在敷衍那位見習生。離開 學堂我編報筆耕幾十年，回想老師那句話，真是醍醐灌頂，點滴在心頭。」 作者回想老師的話感覺「醍醐灌頂」，最主要的原因是：', '["在職場中能保持工作熱情最難能可貴", "個人多年職場的經歷驗證了老師的話", "後輩真的以用功勤奮實現了早年心願", "維持熱情的良方原來是懂得經驗分享"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:26+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "151", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00240', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-112-34c7f7f6', 'sub-customs-f19eb2bd-01', NULL, 'single_choice', '「《生命中不能承受之輕》書中問著：『她終於找回了當年失去的父母嗎？ 她終於找回了她從未有過的孩子嗎？』幸運的是，你有一對兒女；更幸運 的是，因為這一對兒女，身上的層層糾結到你為止；最為幸運的是，經由 兒子與女兒，你終於找回……久遠以前失去的東西。」 根據上文，下列選項何者最切近文中的「你」看待兒女的態度？', '["上天的恩賜", "終老的依靠", "私有的財產", "親情的依存"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:26+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "151", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00241', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-112-34c7f7f6', 'sub-customs-f19eb2bd-01', NULL, 'single_choice', '「老樹啊！你以濃鬱的蔭涼與市民朝夕相處，你以門神之姿捍衛這座舊城 的傳統。」 根據上文，下列選項最符合舊城老樹「門神」特質的是：', '["質樸親切", "輕盈靈巧", "優雅柔美", "雄偉挺拔"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:26+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "151", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00242', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-112-34c7f7f6', 'sub-customs-f19eb2bd-01', NULL, 'single_choice', '「沒有人能事先預見所有的危機，但有個方法可以降低損害，就是避免單 點故障。要是許多事情都仰賴某件事才能運作，而那件事出問題了，就會 成為嚴重的災難。」 下列說明，最能表達此段文字主旨的是：', '["分散風險", "提前布署", "慎勿落單", "沉著鎮定"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:26+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "151", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00243', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-112-34c7f7f6', 'sub-customs-f19eb2bd-01', NULL, 'single_choice', '「流行歌曲足以打動人心，獲得支持的主要原因，在於創作者與受眾之間 並不需要繁雜的手續與作業，便能『共構』出療癒人心的新意義。1950年 代戒嚴令的箝制下，除了船員、漁民外，臺灣大多數的民眾都難有離開陸 地的機會。在這種時代狀況下，如果我們不把港歌中的海／港視為實境， 而將之當作漂泊、不安、挫折、徬徨無助、遠行、離散的象徵，便能對於 港歌風潮的出現，獲得合乎社會發展邏輯的解釋。」 根據上文，下列選項何者最符合文意？', '["戒嚴時期的流行歌曲，往往需要繁雜的手續與作業，才能發行唱片", "具有療癒人心功用的歌曲，往往是符合社會發展邏輯而能賺人熱淚", "1950年代臺灣有大量的漁民、船員，是社會中堅，促進港歌風潮出現", "港歌情境衍伸為生活遭遇與感受的象徵，是其擴大影響力的重要因素"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:26+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "151", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00244', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-112-34c7f7f6', 'sub-customs-f19eb2bd-01', NULL, 'single_choice', '「一個成功的領導者必須先將自己降低為『僕人』，做出根植於愛的犧牲 奉獻，與部屬建立愛與信任，激勵團隊發揮最大的潛能，為達成共同目標 而奮戰不懈。」 根據上文，下列選項何者正確？', '["不以位高而自恃，願意與部屬同心協力以挑戰未來", "領導人的身段愈低愈得民心，對外行銷可無往不利", "以激發團隊每個人最大潛能為目標，共營團隊績效", "為部屬做牛做馬在所不惜，可換得部屬的忠心耿耿"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:26+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "151", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00245', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-112-34c7f7f6', 'sub-customs-f19eb2bd-01', NULL, 'single_choice', '「如果你關注與其他投資人一樣的投資機會、投資每個人都認為會成功的 新創，那你會有一定程度的成績。但是，如果你想從粗糲中找到鑽石，找 到可能帶來超額報酬、非常特殊的新創，你就必須去別人不關注的地方， 也就是要找別人低估或忽視的機會。」 根據上文，下列選項何者最符合文意？', '["注意市場趨勢追捧成功新創", "投資熱門的科技發展新產品", "留心尚未萌芽的前瞻新事業", "認識新創就是市場中的鑽石"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:26+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "151", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00246', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-112-34c7f7f6', 'sub-customs-f19eb2bd-01', NULL, 'single_choice', '「在滑世代中，觀看電影比以往更容易，除了走進電影院外，還有許多影 音串流平臺，隨時可以跟世界接軌。雖然觀看管道變多，但不變的是那種 大家一起待在共同空間中，同看一部電影的『儀式感』。隨著電影情節的 高低起伏，我們一起經歷冒險、體驗苦難，最後一同成長，這種一起笑、 一起哭、一起驚呼、一起療癒的過程，雖然每個人都是獨立的個體，卻不 再感到寂寞。」 根據上文，作者認為一起看電影的「儀式感」最可能的意義在於：', '["讓滑世代的孩子從網路世界抽離，面對現實考驗", "透過共同的觀看經驗，可形成記憶與話題的連結", "善於運用影音串流平臺的便利，以豐富娛樂生活", "集體觀看以刺激實體影音消費，促進影視的發展"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:26+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "151", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL)
